   386→      // Refresh the task list
   387→      handleRefreshFeatures();
   388→    } catch (error) {
   389→      console.error('Failed to update task status after execution:', error);
   390→    }
   391→  }, [activeProjectId, projects, handleRefreshFeatures]);
