   431→          <Alert
   432→            variant="danger"
   433→            title="Backend Connection Error"
   434→            isInline
   435→          >
   436→            {connectionError}
   437→            <br />
   438→            <code style={{ display: 'block', marginTop: 8, padding: 8, background: '#1e1e1e', borderRadius: 4 }}>
   439→              cd /Users/anotonio.silva/antonio/HQ && bun run server/index.ts
   440→            </code>
   441→          </Alert>
   442→        </PageSection>
   443→      )}
   444→
   445→      {/* Tab Bar */}
   446→      <TabBar
   447→        projects={projects}
   448→        activeProjectId={activeProjectId || ''}
   449→        onSelect={handleSelectProject}
   450→        onClose={handleCloseProject}
   451→        onAdd={handleAddProject}
   452→        onReorder={handleReorderProjects}
