   461→            icon={FolderIcon}
   462→          >
   463→            <EmptyStateBody>
   464→              Open a Harness project to start managing your AI agent development sessions.
   465→              Projects with a <code>.harness</code> directory can be opened and tracked.
   466→            </EmptyStateBody>
   467→            <EmptyStateFooter>
   468→              <EmptyStateActions>
   469→                <Button
   470→                  variant="primary"
