   557→                    </EmptyStateBody>
   558→                  </EmptyState>
   559→                )}
   560→              </CardBody>
   561→            </Card>
   562→          </PageSection>
   563→
   564→          {/* Terminal Panel */}
   565→          <PageSection>
   566→            <TerminalPanel height={250} />
   567→          </PageSection>
   568→        </>
   569→      )}
   570→
   571→      {/* Project Selector Dialog */}
   572→      <ProjectSelector
   573→        isOpen={isProjectSelectorOpen}
   574→        onClose={() => setIsProjectSelectorOpen(false)}
