import { useState, useCallback, useEffect } from 'react';
import {
  Button,
  Card,
  CardBody,
  CardTitle,
  Content,
  EmptyState,
  EmptyStateBody,
  EmptyStateFooter,
  EmptyStateActions,
  Label,
  Masthead,
  MastheadBrand,
  MastheadMain,
  Page,
  PageSection,
  Spinner,
  Title,
  Alert,
} from '@patternfly/react-core';
import { FolderOpenIcon, CogIcon, FolderIcon } from '@patternfly/react-icons';
import { TabBar, KanbanBoard, LogPanel, TerminalPanel, ProjectSelector, ProgressCard, Settings, TaskModal, TaskExecutionModal } from './components';
import type { HQSettings, TaskData } from './components';
import type { LogEntry } from './components';
import type { Project, Feature } from './state/store';
import {
  isBackendAvailable,
  runHarnessCommand,
  onPtyOutput,
} from './lib/rpc';

// Process info for log panel
interface ProcessInfo {
  id: string;
  name: string;
}

// Initialize harness database if it doesn't exist
async function initializeHarnessIfNeeded(projectPath: string): Promise<boolean> {
  try {
    // Try to run status command - if it fails, db doesn't exist
    await runHarnessCommand(projectPath, ['db', 'status']);
    return true; // Already initialized
  } catch {
    // Database doesn't exist, initialize it
    try {
      await runHarnessCommand(projectPath, ['init']);
      console.log('Harness database initialized for:', projectPath);
      return true;
    } catch (initError) {
      console.error('Failed to initialize harness:', initError);
      return false;
    }
  }
}

// Fetch tasks from harness CLI and convert to Feature format
async function fetchProjectFeatures(projectPath: string): Promise<Feature[]> {
  try {
    const result = await runHarnessCommand(projectPath, ['task', 'list', '--format', 'json']);

    const response = JSON.parse(result);
    // CLI returns paginated response: { items: [...], has_next, has_prev, ... }
    const tasks = response.items || response;
    if (!Array.isArray(tasks)) return [];

    return tasks.map((task: {
      id: string;
      title: string;
      description?: string;
      status: string;
      category?: string;
      is_passed?: boolean;
    }) => ({
      id: task.id,
      description: task.title,
      category: task.category || 'general',
      priority: 'medium',
      status: task.status.toLowerCase(),
      passes: task.is_passed || task.status.toLowerCase() === 'done',
      steps: task.description ? [task.description] : [],
    }));
  } catch (error) {
    console.error('Failed to fetch project features:', error);
    return [];
  }
}

function App() {
  // Backend connection state
  const [isConnected, setIsConnected] = useState(false);
  const [connectionError, setConnectionError] = useState<string | null>(null);

  // Project state - start empty, no mock projects
  const [projects, setProjects] = useState<Project[]>([]);
  const [activeProjectId, setActiveProjectId] = useState<string | null>(null);

  // Features state - fetched from harness CLI
  const [features, setFeatures] = useState<Feature[]>([]);
  const [isLoadingFeatures, setIsLoadingFeatures] = useState(false);

  // Project selector dialog state
  const [isProjectSelectorOpen, setIsProjectSelectorOpen] = useState(false);

  // Settings dialog state
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [settings, setSettings] = useState<HQSettings>({
    theme: 'system',
    logBufferSize: 10000,
    defaultShell: '/bin/zsh',
    ptyRows: 24,
    ptyCols: 80,
    autoScrollLogs: true,
    showTimestamps: true,
  });

  // Log state - starts empty, filled by PTY events
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [processes, setProcesses] = useState<ProcessInfo[]>([]);

  // Task modal state
  const [isTaskModalOpen, setIsTaskModalOpen] = useState(false);
  const [editingTask, setEditingTask] = useState<Feature | undefined>(undefined);

  // Task execution modal state
  const [isExecutionModalOpen, setIsExecutionModalOpen] = useState(false);
  const [executingTask, setExecutingTask] = useState<Feature | null>(null);

  // Check backend connection on mount
  useEffect(() => {
    const checkConnection = async () => {
      const available = await isBackendAvailable();
      setIsConnected(available);
      if (!available) {
        setConnectionError('Backend server not available. Please start the server with: bun run server/index.ts');
      } else {
        setConnectionError(null);
      }
    };

    checkConnection();
    // Check every 5 seconds
    const interval = setInterval(checkConnection, 5000);
    return () => clearInterval(interval);
  }, []);

  // Open project selector on first launch if no projects
  useEffect(() => {
    if (projects.length === 0 && isConnected) {
      setIsProjectSelectorOpen(true);
    }
  }, [isConnected]);

  // Fetch features when active project changes (initialize harness if needed)
  useEffect(() => {
    const activeProject = projects.find(p => p.id === activeProjectId);
    if (activeProject && isConnected) {
      setIsLoadingFeatures(true);
      // First ensure harness is initialized, then fetch features
      initializeHarnessIfNeeded(activeProject.path)
        .then((initialized) => {
          if (initialized) {
            return fetchProjectFeatures(activeProject.path);
          }
          return [];
        })
        .then(setFeatures)
        .finally(() => setIsLoadingFeatures(false));
    } else {
      setFeatures([]);
    }
  }, [activeProjectId, projects, isConnected]);

  // Listen for PTY output events to populate logs
  useEffect(() => {
    if (!isConnected) return;

    let unlistenFn: (() => void) | null = null;

    const setupListener = async () => {
      try {
        unlistenFn = await onPtyOutput((payload) => {
          const { id, data } = payload;

          // Add process if not already tracked
          setProcesses(prev => {
            if (!prev.find(p => p.id === id)) {
              return [...prev, { id, name: `Process ${id.slice(0, 8)}` }];
            }
            return prev;
          });

          // Add log entry
          setLogs(prev => {
            const newLogs = [...prev, {
              timestamp: Date.now(),
              processId: id,
              processName: `Process ${id.slice(0, 8)}`,
              message: data,
              level: 'info' as const,
            }];
            // Keep only last N logs based on settings
            return newLogs.slice(-settings.logBufferSize);
          });
        });
      } catch (err) {
        console.error('Failed to setup PTY listener:', err);
      }
    };

    setupListener();

    return () => {
      if (unlistenFn) {
        unlistenFn();
      }
    };
  }, [isConnected, settings.logBufferSize]);

  const handleClearLogs = useCallback(() => {
    setLogs([]);
  }, []);

  // Tab handlers
  const handleSelectProject = useCallback((projectId: string) => {
    setActiveProjectId(projectId);
  }, []);

  const handleCloseProject = useCallback((projectId: string) => {
    setProjects((prev) => {
      const filtered = prev.filter((p) => p.id !== projectId);
      // If closing active tab, switch to previous or next
      if (activeProjectId === projectId && filtered.length > 0) {
        const idx = prev.findIndex((p) => p.id === projectId);
        const newActive = filtered[Math.max(0, idx - 1)];
        setActiveProjectId(newActive.id);
      } else if (filtered.length === 0) {
        setActiveProjectId(null);
      }
      return filtered;
    });
  }, [activeProjectId]);

  const handleAddProject = useCallback(() => {
    setIsProjectSelectorOpen(true);
  }, []);

  // Handle selecting a project from the project selector
  const handleSelectProjectFromDialog = useCallback((path: string, name: string) => {
    // Check if project is already open
    const existing = projects.find(p => p.path === path);
    if (existing) {
      setActiveProjectId(existing.id);
      return;
    }

    const id = `proj-${Date.now()}`;
    const newProject: Project = {
      id,
      path,
      name,
      harness: {
        progressFile: '.harness/progress.txt',
        featuresFile: '.harness/features.json',
      },
    };
    setProjects((prev) => [...prev, newProject]);
    setActiveProjectId(id);
  }, [projects]);

  const handleReorderProjects = useCallback((order: string[]) => {
    setProjects((prev) => {
      const projectMap = new Map(prev.map((p) => [p.id, p]));
      return order.map((id) => projectMap.get(id)).filter(Boolean) as Project[];
    });
  }, []);

  // Refresh features for active project
  const handleRefreshFeatures = useCallback(() => {
    const activeProject = projects.find(p => p.id === activeProjectId);
    if (activeProject && isConnected) {
      setIsLoadingFeatures(true);
      fetchProjectFeatures(activeProject.path)
        .then(setFeatures)
        .finally(() => setIsLoadingFeatures(false));
    }
  }, [activeProjectId, projects, isConnected]);

  // Task CRUD handlers
  const handleOpenAddTask = useCallback(() => {
    setEditingTask(undefined);
    setIsTaskModalOpen(true);
  }, []);

  const handleOpenEditTask = useCallback((task: Feature) => {
    setEditingTask(task);
    setIsTaskModalOpen(true);
  }, []);

  const handleCloseTaskModal = useCallback(() => {
    setIsTaskModalOpen(false);
    setEditingTask(undefined);
  }, []);

  const handleSaveTask = useCallback(async (taskData: TaskData, taskId?: string) => {
    const activeProject = projects.find(p => p.id === activeProjectId);
    if (!activeProject) {
      throw new Error('No active project selected');
    }

    const args = taskId
      ? ['task', 'update', taskId]
      : ['task', 'add', taskData.title];

    // Add flags for update or creation
    if (taskId) {
      args.push('--title', taskData.title);
    }
    if (taskData.description) {
      args.push('--description', taskData.description);
    }
    args.push('--status', taskData.status.toLowerCase());
    if (taskData.category) {
      args.push('--category', taskData.category);
    }

    try {
      await runHarnessCommand(activeProject.path, args);
      // Refresh the task list
      handleRefreshFeatures();
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      // Extract the actual error from "Harness command failed: Error: ..."
      const match = message.match(/Error:\s*(.+)/);
      throw new Error(match ? match[1] : message);
    }
  }, [activeProjectId, projects, handleRefreshFeatures]);

  const handleDeleteTask = useCallback(async (taskId: string) => {
    const activeProject = projects.find(p => p.id === activeProjectId);
    if (!activeProject) return;

    // Confirm before deleting
    if (!window.confirm('Are you sure you want to delete this task?')) {
      return;
    }

    await runHarnessCommand(activeProject.path, ['task', 'delete', taskId]);

    // Refresh the task list
    handleRefreshFeatures();
  }, [activeProjectId, projects, handleRefreshFeatures]);

  const handleMoveTask = useCallback(async (taskId: string, newStatus: string) => {
    const activeProject = projects.find(p => p.id === activeProjectId);
    if (!activeProject) return;

    try {
      await runHarnessCommand(activeProject.path, ['task', 'update', taskId, '--status', newStatus.toLowerCase()]);
      // Refresh the task list
      handleRefreshFeatures();
    } catch (error) {
      console.error('Failed to move task:', error);
    }
  }, [activeProjectId, projects, handleRefreshFeatures]);

  // Play task - execute with Claude Code
  const handlePlayTask = useCallback((task: Feature) => {
    // First, move task to DOING status
    handleMoveTask(task.id, 'doing');
    // Open the execution modal
    setExecutingTask(task);
    setIsExecutionModalOpen(true);
  }, [handleMoveTask]);

  // Handle task execution complete
  const handleTaskExecutionComplete = useCallback(async (taskId: string, success: boolean) => {
    const activeProject = projects.find(p => p.id === activeProjectId);
    if (!activeProject) return;

    const newStatus = success ? 'done' : 'qa';

    try {
      await runHarnessCommand(activeProject.path, ['task', 'update', taskId, '--status', newStatus]);
      // Refresh the task list
      handleRefreshFeatures();
    } catch (error) {
      console.error('Failed to update task status after execution:', error);
    }
  }, [activeProjectId, projects, handleRefreshFeatures]);

  // Close execution modal
  const handleCloseExecutionModal = useCallback(() => {
    setIsExecutionModalOpen(false);
    setExecutingTask(null);
  }, []);

  // Get active project
  const activeProject = projects.find((p) => p.id === activeProjectId);

  // Calculate stats from actual features
  const stats = {
    completed: features.filter(f => f.status === 'done').length,
    total: features.length,
  };

  const masthead = (
    <Masthead>
      <MastheadMain>
        <MastheadBrand>
          <Title headingLevel="h1" size="xl">HQ</Title>
        </MastheadBrand>
        <Label color="blue" isCompact>Harness Orchestrator</Label>
        <Label
          color={isConnected ? 'green' : 'red'}
          isCompact
          style={{ marginLeft: 8 }}
        >
          {isConnected ? 'Connected' : 'Disconnected'}
        </Label>
      </MastheadMain>
    </Masthead>
  );

  return (
    <Page masthead={masthead}>
      {/* Connection Error Alert */}
      {connectionError && (
        <PageSection>
          <Alert
            variant="danger"
            title="Backend Connection Error"
            isInline
          >
            {connectionError}
            <br />
            <code style={{ display: 'block', marginTop: 8, padding: 8, background: '#1e1e1e', borderRadius: 4 }}>
              cd /Users/anotonio.silva/antonio/HQ && bun run server/index.ts
            </code>
          </Alert>
        </PageSection>
      )}

      {/* Tab Bar */}
      <TabBar
        projects={projects}
        activeProjectId={activeProjectId || ''}
        onSelect={handleSelectProject}
        onClose={handleCloseProject}
        onAdd={handleAddProject}
        onReorder={handleReorderProjects}
      />

      {/* Empty State when no projects */}
      {projects.length === 0 && (
        <PageSection>
          <EmptyState
            titleText="No Projects Open"
            headingLevel="h2"
            icon={FolderIcon}
          >
            <EmptyStateBody>
              Open a Harness project to start managing your AI agent development sessions.
              Projects with a <code>.harness</code> directory can be opened and tracked.
            </EmptyStateBody>
            <EmptyStateFooter>
              <EmptyStateActions>
                <Button
                  variant="primary"
                  icon={<FolderOpenIcon />}
                  onClick={handleAddProject}
                  isDisabled={!isConnected}
                >
                  Open Project
                </Button>
              </EmptyStateActions>
            </EmptyStateFooter>
          </EmptyState>
        </PageSection>
      )}

      {/* Project Content - only show when there's an active project */}
      {activeProject && (
        <>
          <PageSection>
            <Card>
              <CardTitle>{activeProject.name}</CardTitle>
              <CardBody>
                <Content component="p">
                  <strong>Path:</strong> {activeProject.path}
                </Content>
                <Content component="p">
                  <strong>Tasks:</strong> {stats.completed}/{stats.total} complete
                </Content>
                <div style={{ marginTop: '16px', display: 'flex', gap: '8px' }}>
                  <Button
                    variant="secondary"
                    icon={<CogIcon />}
                    onClick={() => setIsSettingsOpen(true)}
                  >
                    Settings
                  </Button>
                  <Button
                    variant="secondary"
                    icon={<FolderOpenIcon />}
                    onClick={handleAddProject}
                  >
                    Open Another Project
                  </Button>
                </div>
              </CardBody>
            </Card>
          </PageSection>

          {/* Progress Card */}
          <PageSection>
            <ProgressCard projectPath={activeProject.path} onRefresh={handleRefreshFeatures} />
          </PageSection>

          {/* Kanban Board */}
          <PageSection>
            <Card>
              <CardTitle>
                Task Board
                {isLoadingFeatures && <Spinner size="md" style={{ marginLeft: 8 }} />}
              </CardTitle>
              <CardBody>
                <KanbanBoard
                  features={features}
                  onAddTask={handleOpenAddTask}
                  onEditTask={handleOpenEditTask}
                  onDeleteTask={handleDeleteTask}
                  onMoveTask={handleMoveTask}
                  onPlayTask={handlePlayTask}
                />
              </CardBody>
            </Card>
          </PageSection>

          {/* Log Panel */}
          <PageSection>
            <Card>
              <CardTitle>Process Logs</CardTitle>
              <CardBody>
                {logs.length > 0 ? (
                  <LogPanel
                    logs={logs}
                    processes={processes}
                    onClear={handleClearLogs}
                    height={300}
                  />
                ) : (
                  <EmptyState titleText="No Logs" headingLevel="h4">
                    <EmptyStateBody>
                      Process logs will appear here when you start a terminal session.
                    </EmptyStateBody>
                  </EmptyState>
                )}
              </CardBody>
            </Card>
          </PageSection>

          {/* Terminal Panel */}
          <PageSection>
            <TerminalPanel height={250} />
          </PageSection>
        </>
      )}

      {/* Project Selector Dialog */}
      <ProjectSelector
        isOpen={isProjectSelectorOpen}
        onClose={() => setIsProjectSelectorOpen(false)}
        onSelectProject={handleSelectProjectFromDialog}
      />

      {/* Settings Dialog */}
      <Settings
        isOpen={isSettingsOpen}
        onClose={() => setIsSettingsOpen(false)}
        onSettingsChange={setSettings}
      />

      {/* Task Modal */}
      <TaskModal
        isOpen={isTaskModalOpen}
        onClose={handleCloseTaskModal}
        onSave={handleSaveTask}
        task={editingTask}
      />

      {/* Task Execution Modal */}
      <TaskExecutionModal
        isOpen={isExecutionModalOpen}
        task={executingTask}
        projectPath={activeProject?.path || ''}
        onClose={handleCloseExecutionModal}
        onComplete={handleTaskExecutionComplete}
      />
    </Page>
  );
}

export default App;

