import {
  Flex,
  FlexItem,
  Card,
  CardHeader,
  CardTitle,
  CardBody,
  Badge,
  Content,
  Button,
  Split,
  SplitItem,
} from '@patternfly/react-core';
import { PlusCircleIcon } from '@patternfly/react-icons';
import { KanbanCard } from './KanbanCard';
import type { Feature } from '../state/store';

export type KanbanBoardProps = {
  features: Feature[];
  onAddTask?: () => void;
  onEditTask?: (task: Feature) => void;
  onDeleteTask?: (taskId: string) => void;
  onMoveTask?: (taskId: string, newStatus: string) => void;
  onPlayTask?: (task: Feature) => void;
};

// Column definitions with status mapping
const COLUMNS = [
  { id: 'backlog', title: 'BACKLOG', statuses: ['backlog'] },
  { id: 'todo', title: 'TODO', statuses: ['todo', 'pending'] },
  { id: 'doing', title: 'DOING', statuses: ['doing', 'in_progress', 'wip'] },
  { id: 'review', title: 'REVIEW', statuses: ['review', 'pr'] },
  { id: 'qa', title: 'QA', statuses: ['qa', 'testing'] },
  { id: 'done', title: 'DONE', statuses: ['done', 'completed', 'passed'] },
] as const;

// Map feature to column based on status and passes flag
function getColumnForFeature(feature: Feature): string {
  // If feature passes, it's DONE regardless of status
  if (feature.passes) {
    return 'done';
  }

  const status = feature.status.toLowerCase();

  for (const column of COLUMNS) {
    if (column.statuses.some((s) => status.includes(s))) {
      return column.id;
    }
  }

  // Default to backlog if status not recognized
  return 'backlog';
}

// Group features by column
function groupByColumn(features: Feature[]): Record<string, Feature[]> {
  const grouped: Record<string, Feature[]> = {};

  // Initialize all columns
  for (const column of COLUMNS) {
    grouped[column.id] = [];
  }

  // Sort features into columns
  for (const feature of features) {
    const columnId = getColumnForFeature(feature);
    grouped[columnId].push(feature);
  }

  // Sort features within each column by priority
  const priorityOrder: Record<string, number> = {
    critical: 0,
    high: 1,
    medium: 2,
    low: 3,
  };

  for (const columnId of Object.keys(grouped)) {
    grouped[columnId].sort((a, b) => {
      const aPriority = priorityOrder[a.priority] ?? 4;
      const bPriority = priorityOrder[b.priority] ?? 4;
      return aPriority - bPriority;
    });
  }

  return grouped;
}

const columnStyles: React.CSSProperties = {
  minWidth: '220px',
  maxWidth: '280px',
  flex: '1 1 220px',
  height: '100%',
  display: 'flex',
  flexDirection: 'column',
};

const columnHeaderStyles: React.CSSProperties = {
  backgroundColor: '#f0f0f0',
  borderBottom: '2px solid #06c',
};

const columnBodyStyles: React.CSSProperties = {
  backgroundColor: '#fafafa',
  flex: 1,
  overflowY: 'auto',
  padding: '8px',
  minHeight: '200px',
};

export function KanbanBoard({
  features,
  onAddTask,
  onEditTask,
  onDeleteTask,
  onMoveTask,
  onPlayTask,
}: KanbanBoardProps) {
  const grouped = groupByColumn(features);

  // Drag and drop handlers
  const handleDragStart = (e: React.DragEvent, taskId: string) => {
    e.dataTransfer.setData('text/plain', taskId);
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, columnId: string) => {
    e.preventDefault();
    const taskId = e.dataTransfer.getData('text/plain');
    if (taskId && onMoveTask) {
      onMoveTask(taskId, columnId);
    }
  };

  return (
    <div
      style={{
        width: '100%',
        overflowX: 'auto',
        padding: '8px 0',
      }}
    >
      {/* Header with Add Task button */}
      <Split style={{ marginBottom: 16 }}>
        <SplitItem isFilled />
        <SplitItem>
          {onAddTask && (
            <Button variant="primary" icon={<PlusCircleIcon />} onClick={onAddTask}>
              Add Task
            </Button>
          )}
        </SplitItem>
      </Split>

      <Flex
        spaceItems={{ default: 'spaceItemsMd' }}
        alignItems={{ default: 'alignItemsStretch' }}
        style={{ minWidth: 'max-content' }}
      >
        {COLUMNS.map((column) => {
          const columnFeatures = grouped[column.id];
          const count = columnFeatures.length;

          return (
            <FlexItem key={column.id} style={columnStyles}>
              <Card
                isFullHeight
                onDragOver={handleDragOver}
                onDrop={(e) => handleDrop(e, column.id)}
              >
                <CardHeader style={columnHeaderStyles}>
                  <CardTitle>
                    <Flex
                      justifyContent={{ default: 'justifyContentSpaceBetween' }}
                      alignItems={{ default: 'alignItemsCenter' }}
                    >
                      <FlexItem>
                        <strong>{column.title}</strong>
                      </FlexItem>
                      <FlexItem>
                        <Badge isRead={count === 0}>{count}</Badge>
                      </FlexItem>
                    </Flex>
                  </CardTitle>
                </CardHeader>
                <CardBody style={columnBodyStyles}>
                  {columnFeatures.length > 0 ? (
                    columnFeatures.map((feature) => (
                      <KanbanCard
                        key={feature.id}
                        feature={feature}
                        onEdit={onEditTask ? () => onEditTask(feature) : undefined}
                        onDelete={onDeleteTask ? () => onDeleteTask(feature.id) : undefined}
                        onPlay={onPlayTask ? () => onPlayTask(feature) : undefined}
                        onDragStart={(e) => handleDragStart(e, feature.id)}
                        draggable={!!onMoveTask}
                      />
                    ))
                  ) : (
                    <Content
                      component="p"
                      style={{
                        textAlign: 'center',
                        color: '#6a6e73',
                        fontStyle: 'italic',
                        padding: '16px',
                      }}
                    >
                      No tasks
                    </Content>
                  )}
                </CardBody>
              </Card>
            </FlexItem>
          );
        })}
      </Flex>
    </div>
  );
}

export default KanbanBoard;

